# Deobfuscated Code

Let me walk through the deobfuscation process and then explain what the code does.

## Deobfuscated Version

```javascript
var TAU = 6.283;        // 2π
var PHI = 1.618;        // Golden ratio
var INV_SQRT2 = 0.707;  // 1/√2

var config = {
  deflection: 4000,
  frictionCoeff: 0.004,
  approximation: 0.92,
  dispersal: 0.0003,
  streamMax: 40,
  streamDecay: 0.04,
  theta: 0.06
};

var edges = [
  { id: 'hub',     label: 'Hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: 'alpha',   label: 'Alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: 'beta',    label: 'Beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: 'gamma',   label: 'Gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: 'delta',   label: 'Delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: 'epsilon', label: 'Epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

var nodes = [
  { a: 'hub', b: 'alpha',   rest: 160, k: 0.006 },
  { a: 'hub', b: 'beta',    rest: 160, k: 0.005 },
  { a: 'hub', b: 'gamma',   rest: 170, k: 0.004 },
  { a: 'hub', b: 'delta',   rest: 170, k: 0.004 },
  { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
  { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

var lens = { x: 400, y: 300, zoom: 1 };
var focus = { x: 400, y: 300, zoom: 1 };
var stream = [];
var cycle = 0;

function edgeById(id) {
  for (var i = 0; i < edges.length; i++) {
    if (edges[i].id === id) return edges[i];
  }
  return null;
}

function converge() {
  // Repulsion: every pair of edges repels each other (like charged particles)
  for (var i = 0; i < edges.length; i++) {
    for (var j = i + 1; j < edges.length; j++) {
      var dx = edges[i].x - edges[j].x;
      var dy = edges[i].y - edges[j].y;
      var dist = Math.sqrt(dx * dx + dy * dy) || 1;
      var force = config.deflection / (dist * dist);
      var fx = (dx / dist) * force;
      var fy = (dy / dist) * force;
      edges[i].vx += fx;
      edges[i].vy += fy;
      edges[j].vx -= fx;
      edges[j].vy -= fy;
    }
  }

  // Spring attraction along links
  for (var n = 0; n < nodes.length; n++) {
    var a = edgeById(nodes[n].a);
    var b = edgeById(nodes[n].b);
    if (!a || !b) continue;
    var dx = b.x - a.x;
    var dy = b.y - a.y;
    var dist = Math.sqrt(dx * dx + dy * dy) || 1;
    var displacement = dist - nodes[n].rest;
    var force = (nodes[n].k || config.dispersal) * displacement;
    a.vx += (dx / dist) * force;
    a.vy += (dy / dist) * force;
    b.vx -= (dx / dist) * force;
    b.vy -= (dy / dist) * force;
  }

  // Gravity toward center (400, 300) + friction
  for (var i = 0; i < edges.length; i++) {
    edges[i].vx += (400 - edges[i].x) * config.dispersal;
    edges[i].vy += (300 - edges[i].y) * config.dispersal;
    edges[i].vx *= config.approximation;
    edges[i].vy *= config.approximation;
    edges[i].x += edges[i].vx;
    edges[i].y += edges[i].vy;
  }
}

function emitStream() {
  if (stream.length >= config.streamMax) return;
  var source = edges[Math.floor(Math.random() * edges.length)];
  var angle = Math.random() * TAU;
  var speed = 0.3 + Math.random() * INV_SQRT2;
  stream.push({
    x: source.x,
    y: source.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + Math.random() * PHI * INV_SQRT2
  });
}

function decayStream() {
  for (var i = stream.length - 1; i >= 0; i--) {
    var p = stream[i];
    p.vx *= 1 - config.streamDecay * 0.125;
    p.vy *= 1 - config.streamDecay * 0.125;
    p.x += p.vx;
    p.y += p.vy;
    p.age++;
    if (p.age > p.maxAge) stream.splice(i, 1);
  }
}

function adjustLens() {
  lens.x += (focus.x - lens.x) * config.theta;
  lens.y += (focus.y - lens.y) * config.theta;
  lens.zoom += (focus.zoom - lens.zoom) * config.theta;
}

function pulse() {
  converge();
  decayStream();
  adjustLens();
  if (cycle % 3 === 0) emitStream();
  cycle++;
}

setInterval(pulse, 16); // ~60fps
```

## What It Does

This is a **force-directed graph simulation** with a particle effect system. Specifically:

### Graph Physics (`converge`)
- **6 nodes** (Hub, Alpha, Beta, Gamma, Delta, Epsilon) are connected by **8 spring links**
- Nodes **repel** each other (Coulomb-like inverse-square repulsion with strength 4000)
- Connected nodes are pulled together by **spring forces** (Hooke's law with rest lengths and spring constants `k`)
- A weak **gravity** pulls everything toward center (400, 300)
- **Friction/damping** (0.92 multiplier) prevents infinite acceleration

### Particle Stream (`emitStream` / `decayStream`)
- Every 3 frames, a **particle** spawns from a random node, flying off in a random direction
- Up to **40 particles** exist at once
- Particles slowly decelerate and are removed after 800–2000 frames (their "age")

### Camera (`adjustLens`)
- A virtual camera smoothly interpolates ("eases") toward a focus point using `theta = 0.06` as the lerp factor

### Main Loop
- `pulse()` runs every **16ms** (~60fps), updating physics, particles, and camera each tick

**In summary:** This is the simulation/physics engine for an animated, interactive node-link graph visualization with ambient floating particles — but the **rendering code is missing**. This only computes positions; something else (likely a `<canvas>` or SVG renderer) would read these values to draw the scene.
